import upperFirst from './upperFirst';

function minHeight(val: number) {
  return `(min-height: ${val}px)`;
}

function minWidth(val: number) {
  return `(min-width: ${val}px)`;
}

function maxWidth(val: number) {
  return `(max-width: ${val - 1}px)`;
}

/**
 *
 * @param {object} breakPoints Key/value pairs of named breakpoints and widths
 * @returns Media query rules based on the breakpoint e.g.
 *   {
 *     deviceName: '(min-width: 100px)',
 *     maxDeviceName: '(max-width: 99px)',
 *     onlyDeviceName: '(min-width: 100px) and (max-width: 199px)',
 *     ...
 *   }
 */
function generateMediaQueryRules(devices: { [str: string]: number }): {
  [key: string]: string;
} {
  return Object.entries(devices)
    .sort(([, widthA], [, widthB]) => (widthA > widthB ? 1 : -1))
    .reduce((acc, [name, width], i, arr) => {
      const next = arr[i + 1];
      const from = minWidth(width);
      const to = next && maxWidth(next[1]);
      const max = maxWidth(width);

      acc = {
        ...acc,
        [name]: from,
        [`max${upperFirst(name)}`]: max,
        [`only${upperFirst(name)}`]: next ? `${from} and ${to}` : from,
      };

      return acc;
    }, {});
}

export { minHeight, minWidth, maxWidth, generateMediaQueryRules };
